@namespace Lumeo

@{
    var context = new AlertDialogContext(EffectiveOpen, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId, TryDismiss, _descriptionRegistry, RegisterDescription, UnregisterDescription);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// Uncontrolled initial open state (Radix <c>defaultOpen</c>). Used only
    /// when the consumer does NOT bind <see cref="Open"/>: the dialog then owns
    /// its open state internally, seeded from this value. Ignored when
    /// <see cref="Open"/> is supplied (controlled mode).
    /// </summary>
    [Parameter] public bool DefaultOpen { get; set; }

    /// <summary>
    /// Fires before any user-initiated dismiss (Escape key, the Cancel
    /// button, or the Action button). Set
    /// <see cref="DismissEventArgs.Cancel"/> to <c>true</c> to abort. The
    /// <see cref="DismissEventArgs.Reason"/> tells you which path fired
    /// (<c>"escape"</c>, <c>"cancel"</c>, <c>"action"</c>).
    /// </summary>
    [Parameter] public EventCallback<DismissEventArgs> OnBeforeClose { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = LumeoIds.New("alertdialog-title");
    private readonly string _descriptionId = LumeoIds.New("alertdialog-desc");

    // Tracks whether an <AlertDialogDescription> is actually present in the tree.
    // A mutable holder (not a record field) because the cascaded context is
    // rebuilt every render, but the registration must persist across renders.
    private readonly AlertDialogDescriptionRegistry _descriptionRegistry = new();

    // Controlled-vs-uncontrolled disambiguation: a bool param can't be
    // "undefined", so we inspect which parameters the consumer actually supplied.
    private bool _controlled;
    private bool _open;

    private bool EffectiveOpen => _controlled ? Open : _open;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        // The legacy IsOpen alias is obsolete but still a valid bound parameter,
        // so we must honour it when deciding controlled-ness (suppress CS0618 for
        // the nameof — we're intentionally probing the alias).
#pragma warning disable CS0618
        _controlled = parameters.TryGetValue<bool>(nameof(Open), out _)
            || parameters.TryGetValue<bool>(nameof(IsOpen), out _)
            || OpenChanged.HasDelegate;
#pragma warning restore CS0618
        return base.SetParametersAsync(parameters);
    }

    protected override void OnInitialized()
    {
        if (!_controlled) _open = DefaultOpen;
    }

    private async Task SetOpen(bool value)
    {
        _open = value;
        Open = value;
        await OpenChanged.InvokeAsync(value);
        // Re-render so the cascaded context picks up EffectiveOpen — the
        // Escape/Cancel paths reach here via TryDismiss as a direct method call,
        // so an uncontrolled dialog (no OpenChanged) needs this to close.
        StateHasChanged();
    }

    // Called by AlertDialogDescription on init so AlertDialogContent only wires
    // aria-describedby when a description actually exists (no dangling IDREF).
    // Re-renders so the content's aria-describedby picks up the registration on
    // the next pass (child OnInitialized runs after the parent's first render).
    // Counted (not a bool) so a description that is conditionally REMOVED while
    // the dialog stays mounted is correctly un-registered via UnregisterDescription
    // below (Codex P2) — a bare bool latched true forever.
    private void RegisterDescription()
    {
        _descriptionRegistry.Count++;
        if (_descriptionRegistry.Count == 1) StateHasChanged();
    }

    // Called by AlertDialogDescription.Dispose when it is removed from the tree.
    // Only re-renders on the 1->0 transition.
    private void UnregisterDescription()
    {
        _descriptionRegistry.Count--;
        if (_descriptionRegistry.Count == 0) StateHasChanged();
    }

    private async Task<bool> TryDismiss(string reason)
    {
        if (OnBeforeClose.HasDelegate)
        {
            var args = new DismissEventArgs { Reason = reason };
            await OnBeforeClose.InvokeAsync(args);
            if (args.Cancel) return false;
        }
        await SetOpen(false);
        return true;
    }

    // DescriptionRegistry + RegisterDescription/UnregisterDescription default to null! so the 4.0
    // additions stay a non-breaking signature change: Lumeo always constructs the context with real
    // values, and any external 3.x constructor of the 5-arg shape still compiles.
    public record AlertDialogContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId, Func<string, Task<bool>> TryDismiss, AlertDialogDescriptionRegistry DescriptionRegistry = null!, Action RegisterDescription = null!, Action UnregisterDescription = null!);

    /// <summary>
    /// Persistent, mutable holder that survives the per-render rebuild of
    /// <see cref="AlertDialogContext"/>. Lets <see cref="AlertDialogContent"/>
    /// know whether an <see cref="AlertDialogDescription"/> is CURRENTLY rendered
    /// so it can avoid emitting a dangling <c>aria-describedby</c> IDREF. A count,
    /// not a bool, so a description that mounts then is later removed un-registers.
    /// </summary>
    public sealed class AlertDialogDescriptionRegistry
    {
        public int Count { get; set; }
        public bool HasDescription => Count > 0;
    }
}

@namespace Lumeo

<button class="@CssClass" disabled="@IsLoading" @onclick="DoAction" @attributes="AdditionalAttributes">
    @if (IsLoading)
    {
        <Spinner Class="h-4 w-4 me-2" />
    }
    @ChildContent
</button>

@code {
    [CascadingParameter] public AlertDialog.AlertDialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public EventCallback OnAction { get; set; }
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none bg-destructive text-destructive-foreground shadow hover:bg-destructive/90 h-9 px-4 py-2 disabled:pointer-events-none disabled:opacity-50", Class);

    private async Task DoAction()
    {
        await OnAction.InvokeAsync();
        if (!IsLoading)
        {
            // Route the auto-close through the gate so OnBeforeClose can
            // veto with reason="action" (e.g. validation failed mid-action).
            // The OnAction handler itself still ran — only the close is
            // guarded.
            await Context.TryDismiss("action");
        }
    }
}

@namespace Lumeo

@* data-lumeo-initial-focus — AlertDialogContent points its focus trap at this
   marker so initial focus lands on the LEAST destructive action (this Cancel
   button) rather than the first focusable element, per the WAI-ARIA
   alertdialog pattern / Radix behaviour. *@
<button class="@CssClass" data-lumeo-initial-focus @onclick="Cancel" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [CascadingParameter] public AlertDialog.AlertDialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none border border-input bg-background shadow-sm hover:bg-accent hover:text-accent-foreground h-9 px-4 py-2 mt-2 sm:mt-0", Class);

    // Route through TryDismiss so OnBeforeClose handlers can guard the
    // cancel button (reason="cancel") just like Escape / Action paths.
    private async Task Cancel() => await Context.TryDismiss("cancel");
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable
@implements IOverlayExitCallback

@if (Context.IsOpen || _exiting)
{
    @* pointer-events-none wrapper + -auto on backdrop/panel — see DialogContent
       (B4 hardening: the full-viewport wrapper must never be a hit-target). *@
    <div class="fixed inset-0 flex items-center justify-center pointer-events-none" style="z-index:@BackdropZ">
        @* Backdrop — theme-aware --color-overlay-backdrop token via inline style
           (see DialogContent for why inline style not a Tailwind utility). Fades
           out alongside the panel while exiting (service-opened only). *@
        <div class="@BackdropClass" style="background-color:var(--color-overlay-backdrop);z-index:@BackdropZ"></div>
        @* @onkeydown:stopPropagation — keys handled inside this modal must not
           bubble into ancestor overlays (an Escape would cascade-close them).
           See DialogContent for the full rationale. aria-modal drops to false
           while exiting (affordances already torn down — mirrors SheetContent #185). *@
        <div id="@_contentId" class="@CssClass" style="z-index:@ContentZ" role="alertdialog" aria-modal="@(Context.IsOpen ? "true" : "false")" aria-labelledby="@Context.TitleId" aria-describedby="@DescribedBy" @onkeydown="HandleKeyDown" @onkeydown:stopPropagation tabindex="-1" inert="@ExitInert" @attributes="AdditionalAttributes">
            @ChildContent
        </div>
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public AlertDialog.AlertDialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>When <c>true</c> (the default), closing keeps the panel mounted for
    /// a brief zoom-out (and backdrop fade-out) before unmounting instead of
    /// vanishing instantly — so a declarative alert dialog animates its close the
    /// same way <see cref="OverlayProvider"/> already animates service-opened ones.
    /// Set to <c>false</c> to opt OUT (immediate unmount) for tests or consumers
    /// who want an instant dismiss.</summary>
    [Parameter] public bool PlayExitAnimation { get; set; } = true;
    /// <summary>Backdrop z-index. Content sits at <c>ZIndex + 1</c>. Defaults
    /// to <see cref="OverlayService.BaseZIndex"/>; <see cref="OverlayProvider"/>
    /// supplies an incrementing value per nested overlay.</summary>
    [Parameter] public int ZIndex { get; set; } = OverlayService.BaseZIndex;
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("alertdialog");
    // True once we've rendered open and not yet processed the close. Drives the
    // exit animation INDEPENDENTLY of whether the open-interop finished — a dismiss
    // during the Blazor Server interop round-trip window still zooms out instead of
    // vanishing (the B11 "no exit animation on real apps" regression). See
    // SheetContent for the full write-up.
    private bool _shownOpen;
    // True once the open-interop chain (scroll lock + focus trap + slide-end) has
    // run and needs tearing down on close. On Server the panel is visible and
    // dismissable before this flips true.
    private bool _interopReady;
    // Exit-animation state — see DialogContent. Only set when PlayExitAnimation
    // is true (service-opened alert dialogs).
    private bool _exiting;
    private readonly Lumeo.Services.DelayedDispatch _exitDispatch = new();
    // Radix-Presence parity: the real unmount is driven by the panel's own
    // animationend (attachOverlayExitEnd), which also clears the open-time inline
    // animation:none guard so the zoom-out can run. _exitDispatch is the fallback.
    private DotNetObjectReference<AlertDialogContent>? _selfRef;
    private bool _exitWired;

    // FALLBACK window only — the real unmount is the panel's animationend
    // (OnExitAnimationEnd). Sits above the 0.15s zoom-out so the timer never
    // preempts a slightly-late animationend; covers only the JS-dead / lost-event
    // case. 0 only when the exit is opted OUT (PlayExitAnimation=false) → immediate
    // unmount.
    private int ExitDurationMs => PlayExitAnimation ? 280 : 0;

    private int BackdropZ => ZIndex;
    private int ContentZ => ZIndex + 1;

    // The exiting backdrop KEEPS pointer-events-auto so it goes on shielding the
    // page beneath until it unmounts — a modal backdrop must block the page until
    // it is gone (Radix keeps the overlay blocking until close completes).
    // AlertDialog's backdrop has NO click-to-dismiss handler at all, so there is
    // nothing to re-trigger; it simply swallows stray clicks during the fade. The
    // PANEL stays pointer-events-none + inert (PointerClass / ExitInert).
    private string BackdropClass => _exiting
        ? "fixed inset-0 animate-fade-out pointer-events-auto"
        : "fixed inset-0 animate-fade-in pointer-events-auto";

    private string AnimationClass => _exiting ? "animate-zoom-out" : "animate-zoom-in";

    // Exit-window inertness (mirrors DropdownMenuContent / DialogContent). While the
    // panel is kept mounted for the zoom-out (Context.IsOpen == false) its focus trap
    // + scroll lock are already torn down, so make the fading panel pointer-events-none
    // + inert: no stray click / Tab can re-enter a closing alert dialog. Focus was
    // restored to the trigger by RemoveFocusTrap at close time, independent of this.
    private string PointerClass => _exiting ? "pointer-events-none" : "pointer-events-auto";
    private string? ExitInert => _exiting ? "true" : null;

    // Only reference the description id when an <AlertDialogDescription> was
    // actually rendered; otherwise aria-describedby would dangle to a missing
    // element (returning null makes Blazor omit the attribute entirely).
    private string? DescribedBy => Context.DescriptionRegistry.HasDescription ? Context.DescriptionId : null;

    private string CssClass => Cx.Merge("relative grid w-full max-w-lg gap-4 bg-background p-6 shadow-lg sm:rounded-lg", AnimationClass, PointerClass, Class);

    protected override void OnParametersSet()
    {
        // The exit animation is driven ENTIRELY here, from the open->closed render
        // transition, decoupled from the open-interop completion (the old `_wasOpen`
        // gate). On Blazor Server the open interop is a chain of round-trips; keying
        // the zoom-out off `_shownOpen` (flipped true the instant we first render
        // open) makes it play whenever the dismiss lands, and scheduling the unmount
        // here means the panel is never stranded mounted. Opting the exit OUT
        // (PlayExitAnimation=false) keeps ExitDurationMs == 0 → immediate unmount.
        // (B11.)
        if (Context.IsOpen)
        {
            if (_exiting)
            {
                _exitDispatch.Cancel();
                _exiting = false;
                _exitWired = false;
            }
            _shownOpen = true;
        }
        else if (_shownOpen)
        {
            _shownOpen = false;
            if (ExitDurationMs > 0)
            {
                _exiting = true;
                _exitWired = false;
                _exitDispatch.Schedule(ExitDurationMs, () => InvokeAsync(FinishExit));
            }
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_interopReady)
        {
            // Mark BEFORE the awaits so a dismiss Server-dispatched between the
            // interop round-trips hits the undo-check below exactly once.
            _interopReady = true;
            try
            {
                await Interop.LockScroll();
                // Initial focus goes to the least destructive action — the Cancel
                // button carries the data-lumeo-initial-focus marker (WAI-ARIA
                // alertdialog pattern). Falls back to the first focusable element
                // when no AlertDialogCancel is present.
                await Interop.SetupFocusTrap(_contentId, "[data-lumeo-initial-focus]");
                // Neutralize animate-zoom-in after it finishes so the settled panel
                // stops being a containing block for position:fixed descendants —
                // see DialogContent for the full rationale (B1).
                await Interop.AttachOverlaySlideEnd(_contentId);
            }
            catch (JSDisconnectedException) { }

            // Dismissed while the open interop was still in flight (the Server
            // round-trip window that used to swallow the zoom-out): tear the
            // scroll lock / focus trap back down. The zoom-out itself is owned by
            // OnParametersSet, so it plays regardless.
            if (!Context.IsOpen)
            {
                await Cleanup();
                _interopReady = false;
            }
        }
        else if (!Context.IsOpen && _interopReady)
        {
            // Close: tear down scroll-lock / focus-trap. The zoom-out + deferred
            // unmount are already scheduled by OnParametersSet — this branch is
            // interop teardown only.
            await Cleanup();
            _interopReady = false;
        }

        // Radix-Presence parity: hand the unmount to the panel's OWN exit
        // animationend. attachOverlayExitEnd first strips the open-time inline
        // animation:none/transform:none guard (otherwise it overrides the
        // animate-zoom-out class and the panel can't move — the B11 root cause),
        // then notifies OnExitAnimationEnd once the zoom-out finishes so the
        // backdrop + panel drop together. _exitDispatch stays armed as a fallback.
        if (_exiting && !_exitWired)
        {
            _exitWired = true;
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_contentId, _selfRef); }
            catch (JSDisconnectedException) { }
        }
    }

    // Invoked from JS (attachOverlayExitEnd) when the panel's exit animation ends.
    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    // Ends the exit phase: cancel the fallback timer and drop backdrop + panel in
    // the same render commit. Idempotent with the fallback timer.
    private void FinishExit()
    {
        if (!_exiting) return;
        _exitDispatch.Cancel();
        _exiting = false;
        _exitWired = false;
        StateHasChanged();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // Inert during the exit phase — the dialog is already closing.
        if (e.Key == "Escape" && Context.IsOpen)
        {
            await Context.TryDismiss("escape");
        }
    }

    private async Task Cleanup()
    {
        try
        {
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        _exitDispatch.Dispose();
        _selfRef?.Dispose();
        if (_interopReady)
        {
            await Cleanup();
        }
    }
}

@namespace Lumeo
@implements IDisposable

<p id="@Context.DescriptionId" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</p>

@code {
    [CascadingParameter] public AlertDialog.AlertDialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("text-sm text-muted-foreground", Class);

    protected override void OnInitialized()
        // Signal the root so AlertDialogContent wires aria-describedby to this
        // <p>'s id — without a registered description the IDREF would dangle.
        => Context.RegisterDescription();

    // Un-registers on removal — without this, removing the description while the
    // dialog stays mounted left aria-describedby pointing at an id no longer in the
    // DOM (Codex P2).
    public void Dispose() => Context.UnregisterDescription();
}

